const response = $input.first().json;

// Safely get image URL
if (!response.images || response.images.length === 0) {
  return [
    {
      json: {
        imageUrl: "",
        error: "No images in response"
      }
    }
  ];
}

const imageUrl = response.images[0].url;
const inferenceTime = response.timings ? response.timings.inference : 0;
const seed = response.seed || 0;

return [
  {
    json: {
      imageUrl: imageUrl,
      inferenceTime: inferenceTime,
      seed: seed,
      generatedAt: new Date().toISOString()
    }
  }
];

const response = $input.first().json;

let caption = "A beautiful moment captured forever. #Art #Photography #Creative #Beauty #Inspiration";

if (response.choices && response.choices[0]) {
  caption = response.choices[0].message.content;
}

// Get chatId from static data
const staticData = $getWorkflowStaticData('global');
const chatId = staticData.chatId;

return [
  {
    json: {
      caption: caption,
      chatId: chatId
    }
  }
];

const response = $input.first().json;

let rawContent = "";
if (response.choices && response.choices[0]) {
  rawContent = response.choices[0].message.content;
}

if (!rawContent) {
  return [{ json: { error: "Empty response", raw: response } }];
}

let parsed;
try {
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  } else {
    parsed = JSON.parse(rawContent);
  }
} catch(e) {
  return [{ json: { error: "Could not parse", raw: rawContent } }];
}

// Return single prompt only
const prompt = parsed.prompt || (parsed.prompts && parsed.prompts[0]) || "beautiful scene";

return [
  {
    json: {
      promptNumber: 1,
      prompt: prompt
    }
  }
];

const response = $input.first().json;

if (!response.result || response.result.length === 0) {
  return [];
}

const update = response.result[0];
const message = update.message;
if (!message) return [];
if (!message.photo) return [];

// Check if already processed
const staticData = $getWorkflowStaticData('global');
const lastProcessedId = staticData.lastUpdateId || 0;

if (update.update_id <= lastProcessedId) {
  return [];
}

// Save as processed
staticData.lastUpdateId = update.update_id;

// Get user's description — whatever they typed
const userDescription = (message.caption || "make it artistic and beautiful").trim();
const chatId = message.chat.id;

// Get highest quality photo
const photos = message.photo;
const fileId = photos[photos.length - 1].file_id;

// Save to static data
staticData.userDescription = userDescription;
staticData.chatId = chatId;

return [
  {
    json: {
      fileId: fileId,
      userDescription: userDescription,
      chatId: chatId
    }
  }
];

const response = $input.first().json;

let filePath = null;
if (response.result && response.result.file_path) {
  filePath = response.result.file_path;
}

if (!filePath) {
  return [{ json: { error: "No file path found" } }];
}

const botToken = "YOUR_TELEGRAM_BOT_TOKEN";
const imageUrl = `https://api.telegram.org/file/bot${botToken}/${filePath}`;

const staticData = $getWorkflowStaticData('global');

return [
  {
    json: {
      imageUrl: imageUrl,
      userDescription: staticData.userDescription,
      chatId: staticData.chatId
    }
  }
];

const response = $input.first().json;

// Get image analysis from Mistral
let imageAnalysis = "A detailed scene";
if (response.choices && response.choices[0]) {
  imageAnalysis = response.choices[0].message.content;
}

const staticData = $getWorkflowStaticData('global');

return [
  {
    json: {
      imageAnalysis: imageAnalysis,
      userDescription: staticData.userDescription,
      chatId: staticData.chatId
    }
  }
];

