  {
    role: "system",
    content: "Write natural human captions. Never mention AI or technology. Write as if a real artist created this. End with exactly 5 hashtags. Return ONLY the caption text."
  },
  {
    role: "user",
    content: "Image shows: " + imageAnalysis + "\nCreative direction: " + userDescription + "\n\nWrite engaging caption under 100 words with 5 hashtags at the end."
  }
];

return [
  {
    json: {
      imageAnalysis: imageAnalysis,
      userDescription: userDescription,
      chatId: chatId,
      groqMessages: [
